var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"동생이여, 조심해라!","JPN":"妹よ、気を付けろ！","ENG":"Little sister, be careful!","TWN":"妹妹小心！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"칫……! 알고 있어!","JPN":"ちっ……！　わかってるよ！","ENG":"Tch...! I know!","TWN":"嘖……！我知道啦！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"으앙!? 아파!","JPN":"うわぁ！　痛い！","ENG":"Ouch! It stings!","TWN":"哎呀！好痛喔！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"……어라? 그런데 생각했던 것보다 덜 아프네?","JPN":"……あれ？　でも思ったより痛くない！","ENG":"Huh...? It doesn’t hurt as much as I had expected.","TWN":"……奇怪？可是又好像沒想像中那麼痛？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"음? 하지만 대장이 사용하는 특수탄의 위력은 동생이 버텨낼 정도가 아닌데?","JPN":"うむ？　でも隊長が使う特殊弾の威力は妹が耐えられる程度のものでは\\nないはずだが？","ENG":"Hmm? But the special munition Cap uses should be powerful enough to knock you out.","TWN":"嗯？如果是隊長使用的是特殊彈，那個威力你應該承受不住吧？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"역시, 리더는 처음부터 이런 상황도 내다보고 있었군요.","JPN":"やっぱり、リーダーは最初からこうなることを見込んでいたようですね。","ENG":"Looks like Leader already knew this would happen from the start.","TWN":"果然，老大應該從一開始就有預料到會是這種情況。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"전원! 리더의 공격은 몸으로 받아내면서 육탄전으로 밀어붙여!","JPN":"総員！　リーダーの攻撃を受け止めながら肉弾戦で押し上げよ！","ENG":"Everybody! Block Leader's attack with your body and advance close enough for hand-to-hand combat!","TWN":"全員注意！用身體來擋老大的攻擊，同時使用肉搏戰！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"좋아! 뭔지 몰라도 육탄전이라면 환영이지!","JPN":"よし！　なんだかわからないけど、肉弾戦なら歓迎だよ！","ENG":"Okay! I don’t know what’s going on, but I welcome close combat any day of the week!","TWN":"好欸！雖然聽不太懂，但我最喜歡肉搏戰！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"呃……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"마, 말도 안 돼…….","JPN":"し、信じられない……","ENG":"I-impossible...","TWN":"這…怎麼可能……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내 최강의 기물이…… 여왕이 저런 버러지들에게 밀린다고?","JPN":"私の最強の駒が……クイーンがあんな雑魚どもに押されている？","ENG":"My most powerful piece... How can the queen lose to mere pawns?","TWN":"我最強的棋子……皇后竟然被區區的小兵給逼到牆角？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"웃기지 마……! 그럴 리가 없잖아!","JPN":"ふざけるな……！　そんなわけないわ！","ENG":"It can’t be...! There's no way!","TWN":"想耍我……！我不相信！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"일어나, 신지아!! 이제 장난은 때려치워!","JPN":"起きなさい、ヒメノ・ユイ！！　冗談は終わりよ！","ENG":"Get up, Shin Jia!! Stop fooling around!","TWN":"沈佳，你給我起來！！現在不是開玩笑的時候！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"다시 명령하겠다! 더 나은 세상을 위해……!","JPN":"改めて命令する！　より良い世界のために……！","ENG":"I command you again! For a better world...!!","TWN":"我再次命令你！為了更好的未來……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"커윽……!? 브, 브로치가 깨졌어……?!","JPN":"くうっ……！？　ブ、ブローチが割れた……！？","ENG":"Kuh...! M-my brooch...!!","TWN":"唔……！我的領針…碎了……？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아……?","JPN":"あ……？","ENG":"Huh...?!","TWN":"唔……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐야, 너 언제……!","JPN":"なによ、あんたいつの間に……！","ENG":"How are you...?!","TWN":"什麼，你是什麼時候……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……부회장님께 감사해야겠네요. 비서라면 만년필 한 자루쯤은 가지고 다니라고 하셨거든요.","JPN":"……副会長に感謝します。\\n秘書なら万年筆1本くらいは常に持ち歩きなさいと言われていました。","ENG":"I must thank the Vice Chairman. He always said a secretary should carry a fountain pen at all times.","TWN":"……這都要謝謝副會長，因為副會長說身為秘書，必須要隨身攜帶鋼筆。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"조금 깊이 찔렀지만 양해해 주시죠. 감정이 들어가 버려서요.","JPN":"やや深く刺したのは、ご了承ください。個人的な感情が入ってしまいました。","ENG":"Please excuse me for stabbing a little too deep. Emotions got in the way.","TWN":"不好意思，刺得有點深，因為帶有私人情緒。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"실장님?!","JPN":"室長！？","ENG":"Chief?!","TWN":"室長？！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"저 아줌마! 아직 살아 있었구나!","JPN":"あのおばさん！　まだ生きてたんだね！","ENG":"Look! She’s still alive!","TWN":"那個大嬸！還活著欸！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너……! 죽은 척하고…… 내 브로치를 찌를 기회만 엿보고 있었던 거냐……?!","JPN":"あんた……！　死んだふりをして……\\n私のブローチを狙う機会を伺っていたの……！？","ENG":"You...! Pretending to be dead while waiting for the perfect opportunity to shatter my brooch...?!","TWN":"你是……裝死……然後伺機要破壞我的領針……？！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"분명히 급소에 총을 맞았을 텐데! 어떻게……!","JPN":"確かに急所を撃たれたはずなのに、どうして……！","ENG":"But I saw you get shot! How...?!","TWN":"明明就有打中你的害要！怎麼會……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 아무리 카운터라도 즉사였겠죠.","JPN":"はい。いくらカウンターとはいえ即死だったでしょう。","ENG":"Yes, even a Counter wouldn’t have survived that shot.","TWN":"沒錯，就算是制裁者，被打中也會立刻死亡。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아가씨께서 특수탄을 사용하셨더라면 말입니다.","JPN":"……お嬢様が特殊弾を使ったらの話ですが。","ENG":"If only Miss Jia had used her special bullets, I mean.","TWN":"……但前提是小姐要使用特殊彈。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"특수탄……?!","JPN":"特殊弾……！？","ENG":"Special bullets...?!","TWN":"特殊彈……？！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨께선 카운터 상대로 유효한 특수탄 대신 일반탄으로 무장한 채 여기 오셨을 겁니다.","JPN":"お嬢様はカウンターに対して有効な特殊弾の代わりに、\\n一般の弾で武装してここにいらっしゃったのでしょう。","ENG":"Miss Jia arrived with ordinary bullets rather than the Counter-killing special bullets.","TWN":"小姐的槍裡裝的不是對付制裁者的特殊彈，而是一般的子彈。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……자기 손으로 동료들에게 상처를 입힐 수도 있다고, 직감하셨는지도 모르겠군요.","JPN":"……自らの手で仲間を傷つけることがあるかもしれないと、\\n直感されたのかもしれませんね。","ENG":"Perhaps she foresaw the possibility of harming her comrades with her own hands.","TWN":"……小姐應該是有猜到，自己可能會傷害到夥伴們。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭……! 자기가 조종당할지도 모른다고 예상했다고?","JPN":"くぅ……！　自分が操られるかもしれないと予想しただと？","ENG":"Kuh...! She predicted that she might become a puppet?!","TWN":"什麼……！你說她有猜到自己可能會被控制？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"말도 안 돼…… 그게 뭐야!! 그건, 그건 단서도 흘리지 않았는데……!","JPN":"あり得ない……何なのよ！！　そんな、そんなことは全く匂わせなかったのに……！","ENG":"That can’t be...!! I never mentioned any of it to her before...!","TWN":"這怎麼可能……這是怎麼回事！！又沒有人通風報信……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 저도 처음에는 그렇게 놀라기 일쑤였지만……","JPN":"わかります。私も最初はそのように何度も驚いていましたが……","ENG":"Yes. I was also surprised like you at first...","TWN":"嗯，我一開始也常常嚇到……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이제는 그러려니 합니다. 아가씨께는 참 쉬운 일이니까요.","JPN":"今は当然のことだと思っています。\\nお嬢様にとっては、本当に簡単なことですので。","ENG":"However, I now accept it for what it is. Because for Miss Jia, it comes naturally to her.","TWN":"不過現在已經習以為常，因為對小姐而言，就是那麼的輕而易舉。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너, 네까짓 게……!","JPN":"あんた、あんたごときが……！","ENG":"Why you...!","TWN":"你這傢伙……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"정말로 더 나은 세상을 위해 없어져야 할 건 아가씨가 아냐.","JPN":"より良い世界のために、本当に消えるべき存在はお嬢様ではない。","ENG":"It’s not Miss Jia who needs to disappear in order for the world to be a better place.","TWN":"為了更好的未來，真正必須消失的不是小姐！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"나나 당신처럼……. 속이 썩어 문드러진 속물들이지!","JPN":"私やあなたのように……心が腐りきった俗物だ！","ENG":"It’s the likes of you and I... who should!","TWN":"而是像你和我……這種內心腐敗的人！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};